use data::*;

#[cfg(test)]
use std::sync::Mutex;

#[cfg(not(test))]
extern "C" {
  fn get_read_port(value: *mut vest_1prod_1cons::ArrayOfByte) -> bool;
}

pub fn unsafe_get_read_port() -> vest_1prod_1cons::ArrayOfByte
{
  unsafe {
    let value: *mut vest_1prod_1cons::ArrayOfByte = &mut [0; vest_1prod_1cons::vest_1prod_1cons_ArrayOfByte_DIM_0];
    get_read_port(value);
    return *value;
  }
}

